parameters.jsCode:
const athleteData = {};

for (const item of $input.all()) {
  const skaterName = item.json['Skater Name'];
  if (!athleteData[skaterName]) {
    athleteData[skaterName] = [];
  }
  athleteData[skaterName].push(item.json);
}

const output = [];
for (const [name, sessions] of Object.entries(athleteData)) {
  output.push({
    json: {
      athleteName: name,
      sessions: sessions,
      sessionCount: sessions.length
    }
  });
}

return output;

